// // This is a 1-bit full subtractor module
// Inputs: a, b, cin
// Outputs: diff, borrow
// Implementation: diff = a - b - cin, borrow = (a < b) || ((a == b) && (cin == 1))
module full_adder (
    input wire a,
    input wire b,
    input wire cin,
    output wire sum,
    output wire cout
);

assign sum = a ^ b ^ cin;
assign cout = (a & b) | (b & cin) | (a & cin);

endmodule

